import os

# CSS文件内容
css_content = '''/* ==================== CSS变量定义 ==================== */
:root {
  /* 颜色 */
  --color-bg: #0A0E27;
  --color-neon-pink: #FF10F0;
  --color-neon-blue: #00D9FF;
  --color-neon-green: #39FF14;
  --color-text: #E0E0E0;
  --color-text-secondary: #A0A0A0;

  /* 尺寸 */
  --nav-height: 80px;
  --border-width: 2px;
  --hero-height: 600px;

  /* 过渡 */
  --transition: all 0.3s ease;
}

/* ==================== 全局重置 ==================== */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: 'Arial', sans-serif;
  background-color: var(--color-bg);
  color: var(--color-text);
  line-height: 1.6;
  overflow-x: hidden;
}

/* ==================== 导航栏 ==================== */
nav {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: var(--nav-height);
  background-color: var(--color-bg);
  border-bottom: var(--border-width) solid var(--color-neon-blue);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 40px;
  z-index: 1000;
  box-shadow: 0 0 20px rgba(0, 217, 255, 0.3);
}

.logo {
  font-size: 28px;
  font-weight: bold;
  color: var(--color-neon-pink);
  text-shadow: 0 0 10px var(--color-neon-pink), 0 0 20px rgba(255, 16, 240, 0.5);
  letter-spacing: 2px;
}

.nav-menu {
  display: flex;
  gap: 30px;
  list-style: none;
}

.nav-menu a {
  color: var(--color-text);
  text-decoration: none;
  font-size: 16px;
  transition: var(--transition);
  position: relative;
  padding: 5px 0;
}

.nav-menu a::before {
  content: '';
  position: absolute;
  bottom: -5px;
  left: 0;
  width: 0%;
  height: 2px;
  background-color: var(--color-neon-pink);
  transition: var(--transition);
}

.nav-menu a:hover {
  color: var(--color-neon-pink);
  text-shadow: 0 0 10px var(--color-neon-pink);
}

.nav-menu a:hover::before {
  width: 100%;
}

.hamburger {
  display: none;
  flex-direction: column;
  cursor: pointer;
  gap: 6px;
}

.hamburger span {
  width: 25px;
  height: 3px;
  background-color: var(--color-neon-pink);
  transition: var(--transition);
  border-radius: 2px;
}

.hamburger.active span:nth-child(1) {
  transform: rotate(45deg) translate(10px, 10px);
}

.hamburger.active span:nth-child(2) {
  opacity: 0;
}

.hamburger.active span:nth-child(3) {
  transform: rotate(-45deg) translate(7px, -7px);
}

/* ==================== Hero区域 ==================== */
.hero {
  margin-top: var(--nav-height);
  height: var(--hero-height);
  background: linear-gradient(135deg, rgba(255, 16, 240, 0.1) 0%, rgba(0, 217, 255, 0.1) 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-direction: column;
  position: relative;
  overflow: hidden;
  border-bottom: var(--border-width) solid var(--color-neon-blue);
  box-shadow: inset 0 0 30px rgba(0, 217, 255, 0.2);
}

.hero::before,
.hero::after {
  content: '';
  position: absolute;
  width: 2px;
  height: 80%;
  background: linear-gradient(to bottom, transparent, var(--color-neon-blue), transparent);
  top: 10%;
}

.hero::before {
  left: 10%;
}

.hero::after {
  right: 10%;
}

.hero-content {
  text-align: center;
  z-index: 2;
}

.hero h1 {
  font-size: 72px;
  color: var(--color-neon-pink);
  text-shadow: 0 0 20px var(--color-neon-pink), 0 0 40px rgba(255, 16, 240, 0.8);
  margin-bottom: 20px;
  letter-spacing: 3px;
  animation: glow-pulse 2s ease-in-out infinite;
}

.hero h2 {
  font-size: 48px;
  color: var(--color-neon-blue);
  text-shadow: 0 0 20px var(--color-neon-blue), 0 0 40px rgba(0, 217, 255, 0.8);
  letter-spacing: 2px;
  animation: glow-pulse 2.5s ease-in-out infinite;
}

@keyframes glow-pulse {
  0%, 100% { text-shadow: 0 0 20px currentColor; }
  50% { text-shadow: 0 0 40px currentColor, 0 0 60px rgba(255, 16, 240, 0.5); }
}

/* ==================== 主容器 ==================== */
.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

section {
  padding: 80px 0;
}

section h2 {
  font-size: 48px;
  color: var(--color-neon-pink);
  text-shadow: 0 0 10px var(--color-neon-pink);
  margin-bottom: 60px;
  text-align: center;
  letter-spacing: 2px;
}

/* ==================== 世界观区域 ==================== */
.worldview {
  background-color: rgba(0, 0, 0, 0.3);
}

.worldview-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 30px;
}

.worldview-card {
  background-color: rgba(10, 14, 39, 0.8);
  border: var(--border-width) solid var(--color-neon-pink);
  border-top: 3px solid var(--color-neon-blue);
  padding: 40px;
  text-align: center;
  cursor: pointer;
  transition: var(--transition);
  position: relative;
  overflow: hidden;
}

.worldview-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: linear-gradient(90deg, var(--color-neon-blue), transparent);
}

.worldview-card:hover {
  border-color: var(--color-neon-blue);
  box-shadow: 0 0 30px var(--color-neon-blue), inset 0 0 30px rgba(0, 217, 255, 0.2);
  transform: translateY(-5px);
}

.worldview-card h3 {
  font-size: 24px;
  color: var(--color-neon-blue);
  margin-bottom: 15px;
  text-shadow: 0 0 10px var(--color-neon-blue);
}

.worldview-card p {
  color: var(--color-text-secondary);
  font-size: 14px;
  line-height: 1.8;
}

/* ==================== 主线故事时间线 ==================== */
.main-story {
  background-color: rgba(0, 0, 0, 0.5);
}

.timeline {
  position: relative;
  padding: 40px 0;
}

.timeline::before {
  content: '';
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  width: 2px;
  height: 100%;
  background: linear-gradient(to bottom, var(--color-neon-blue), transparent);
}

.timeline-container {
  display: flex;
  flex-direction: column;
  gap: 50px;
}

.timeline-item {
  display: flex;
  margin-bottom: 40px;
  opacity: 0.8;
  transition: var(--transition);
}

.timeline-item:hover {
  opacity: 1;
}

.timeline-item:nth-child(odd) {
  flex-direction: row;
  justify-content: flex-start;
}

.timeline-item:nth-child(even) {
  flex-direction: row-reverse;
  justify-content: flex-end;
}

.timeline-item:nth-child(odd) .timeline-content {
  margin-right: 50px;
  text-align: right;
}

.timeline-item:nth-child(even) .timeline-content {
  margin-left: 50px;
  text-align: left;
}

.timeline-dot {
  width: 20px;
  height: 20px;
  background-color: var(--color-bg);
  border: var(--border-width) solid var(--color-neon-pink);
  border-radius: 50%;
  flex-shrink: 0;
  margin-top: 5px;
  cursor: pointer;
  transition: var(--transition);
  box-shadow: 0 0 15px rgba(255, 16, 240, 0.5);
}

.timeline-item:hover .timeline-dot {
  width: 28px;
  height: 28px;
  margin-top: 1px;
  background-color: var(--color-neon-pink);
  box-shadow: 0 0 25px var(--color-neon-pink), inset 0 0 10px rgba(255, 16, 240, 0.5);
}

.timeline-content h3 {
  font-size: 24px;
  color: var(--color-neon-pink);
  margin-bottom: 10px;
  text-shadow: 0 0 10px var(--color-neon-pink);
}

.timeline-content p {
  color: var(--color-text-secondary);
  font-size: 14px;
  max-width: 400px;
}

/* ==================== 支线任务网格 ==================== */
.side-quests {
  background-color: rgba(0, 0, 0, 0.3);
}

.quests-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 30px;
}

.quest-card {
  background-color: rgba(10, 14, 39, 0.8);
  border: var(--border-width) solid var(--color-neon-green);
  padding: 30px;
  cursor: pointer;
  transition: var(--transition);
  position: relative;
  overflow: hidden;
}

.quest-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 30px;
  height: 30px;
  border-top: 2px solid var(--color-neon-blue);
  border-left: 2px solid var(--color-neon-blue);
}

.quest-card:hover {
  border-color: var(--color-neon-blue);
  box-shadow: 0 0 30px var(--color-neon-blue), inset 0 0 30px rgba(0, 217, 255, 0.2);
  transform: translateY(-5px);
}

.quest-card h3 {
  font-size: 20px;
  color: var(--color-text);
  margin-bottom: 15px;
  margin-top: 10px;
}

.quest-card p {
  color: var(--color-text-secondary);
  font-size: 14px;
  margin-bottom: 15px;
  line-height: 1.6;
}

.difficulty-tag {
  display: inline-block;
  padding: 5px 15px;
  background-color: transparent;
  border: 1px solid var(--color-neon-pink);
  color: var(--color-neon-pink);
  font-size: 12px;
  font-weight: bold;
  text-shadow: 0 0 5px var(--color-neon-pink);
  border-radius: 3px;
}

/* ==================== 页脚 ==================== */
footer {
  background-color: var(--color-bg);
  border-top: var(--border-width) solid var(--color-neon-blue);
  padding: 60px 0 30px;
  box-shadow: inset 0 20px 40px rgba(0, 217, 255, 0.1);
}

.footer-content {
  text-align: center;
}

.footer-copyright {
  font-size: 24px;
  color: var(--color-neon-pink);
  text-shadow: 0 0 10px var(--color-neon-pink);
  margin-bottom: 30px;
  letter-spacing: 1px;
}

.footer-links {
  display: flex;
  justify-content: center;
  gap: 40px;
  margin-bottom: 20px;
  flex-wrap: wrap;
}

.footer-links a {
  color: var(--color-text-secondary);
  text-decoration: none;
  font-size: 16px;
  transition: var(--transition);
}

.footer-links a:hover {
  color: var(--color-neon-blue);
  text-shadow: 0 0 10px var(--color-neon-blue);
}

.footer-bottom {
  color: var(--color-text-secondary);
  font-size: 12px;
}

/* ==================== 响应式设计 ==================== */
@media (max-width: 1024px) {
  .worldview-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .quests-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .timeline::before {
    left: 20px;
  }

  .timeline-item:nth-child(odd),
  .timeline-item:nth-child(even) {
    flex-direction: row !important;
    justify-content: flex-start !important;
  }

  .timeline-item:nth-child(odd) .timeline-content,
  .timeline-item:nth-child(even) .timeline-content {
    margin-right: 40px !important;
    margin-left: 0 !important;
    text-align: left !important;
  }

  .timeline-dot {
    margin-left: 0;
  }
}

@media (max-width: 768px) {
  nav {
    padding: 0 20px;
  }

  .logo {
    font-size: 20px;
  }

  .nav-menu {
    position: absolute;
    top: var(--nav-height);
    left: 0;
    right: 0;
    flex-direction: column;
    background-color: var(--color-bg);
    border-bottom: 2px solid var(--color-neon-blue);
    max-height: 0;
    overflow: hidden;
    transition: max-height 0.3s ease;
    gap: 0;
  }

  .nav-menu.active {
    max-height: 300px;
  }

  .nav-menu li {
    padding: 15px 20px;
    border-bottom: 1px solid rgba(0, 217, 255, 0.2);
  }

  .nav-menu a {
    display: block;
  }

  .hamburger {
    display: flex;
  }

  .hero h1 {
    font-size: 48px;
  }

  .hero h2 {
    font-size: 32px;
  }

  .hero::before,
  .hero::after {
    display: none;
  }

  section h2 {
    font-size: 36px;
  }

  .worldview-grid,
  .quests-grid {
    grid-template-columns: 1fr;
  }

  .worldview-card,
  .quest-card {
    padding: 20px;
  }

  .timeline-content {
    max-width: 100%;
  }

  .timeline-item:nth-child(odd) .timeline-content,
  .timeline-item:nth-child(even) .timeline-content {
    margin-right: 30px !important;
    margin-left: 0 !important;
  }

  .footer-links {
    gap: 20px;
  }

  .footer-copyright {
    font-size: 18px;
  }
}

/* ==================== 滚动条美化 ==================== */
::-webkit-scrollbar {
  width: 10px;
}

::-webkit-scrollbar-track {
  background: var(--color-bg);
}

::-webkit-scrollbar-thumb {
  background: var(--color-neon-pink);
  border-radius: 5px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--color-neon-blue);
  box-shadow: 0 0 10px var(--color-neon-blue);
}
'''

