import os

# 创建 JavaScript 文件
js_content = '''// 赛博朋克2077网站 - JavaScript 交互逻辑

// DOM 元素缓存
const hamburger = document.querySelector('.hamburger');
const navMenu = document.querySelector('.nav-menu');
const navLinks = document.querySelectorAll('.nav-menu a');
const cards = document.querySelectorAll('.worldview-card, .side-mission-card');
const timelineNodes = document.querySelectorAll('.timeline-node');

// 1. 汉堡菜单切换
if (hamburger) {
  hamburger.addEventListener('click', () => {
    navMenu.classList.toggle('active');
    hamburger.classList.toggle('active');
  });
}

// 2. 点击导航链接时关闭菜单
navLinks.forEach(link => {
  link.addEventListener('click', () => {
    navMenu.classList.remove('active');
    hamburger?.classList.remove('active');
  });
});

// 3. 点击页面其他地方关闭菜单
document.addEventListener('click', (e) => {
  const isHamburger = e.target.closest('.hamburger');
  const isMenu = e.target.closest('.nav-menu');

  if (!isHamburger && !isMenu && navMenu.classList.contains('active')) {
    navMenu.classList.remove('active');
    hamburger?.classList.remove('active');
  }
});

// 4. 卡片悬停效果（CSS 驱动，JS 可选增强）
cards.forEach(card => {
  card.addEventListener('mouseenter', () => {
    card.style.boxShadow = '0 0 30px var(--neon-pink), 0 0 50px var(--neon-blue)';
  });

  card.addEventListener('mouseleave', () => {
    card.style.boxShadow = '';
  });
});

// 5. 时间线节点悬停效果（放大 + 发光）
timelineNodes.forEach(node => {
  node.addEventListener('mouseenter', () => {
    node.style.transform = 'scale(1.3)';
    node.style.boxShadow = '0 0 20px var(--neon-pink), inset 0 0 10px var(--neon-pink)';
  });

  node.addEventListener('mouseleave', () => {
    node.style.transform = 'scale(1)';
    node.style.boxShadow = '';
  });
});

// 6. 平滑滚动
document.querySelectorAll('a[href^="#"]').forEach(link => {
  link.addEventListener('click', (e) => {
    const href = link.getAttribute('href');
    if (href !== '#') {
      e.preventDefault();
      const target = document.querySelector(href);
      if (target) {
        target.scrollIntoView({
          behavior: 'smooth',
          block: 'start'
        });
      }
    }
  });
});

// 7. 滚动时导航栏样式调整（可选）
let lastScrollY = 0;
const navbar = document.querySelector('.navbar');

if (navbar) {
  window.addEventListener('scroll', () => {
    lastScrollY = window.scrollY;

    // 滚动超过100px时添加背景透明度
    if (lastScrollY > 100) {
      navbar.style.backgroundColor = 'rgba(10, 14, 39, 0.95)';
    } else {
      navbar.style.backgroundColor = '';
    }
  });
}

// 8. 支线任务卡片点击效果（可选扩展）
const sideMissionCards = document.querySelectorAll('.side-mission-card');
sideMissionCards.forEach(card => {
  card.addEventListener('click', () => {
    // 可用于未来的模态框或详情展示
    console.log('Side Mission clicked:', card.querySelector('.mission-title').textContent);
  });
});

// 9. 视差滚动效果（可选）
const heroSection = document.querySelector('.hero');
if (heroSection) {
  window.addEventListener('scroll', () => {
    const scrollY = window.scrollY;
    heroSection.style.backgroundPosition = `center ${scrollY * 0.5}px`;
  });
}

// 10. 响应式检查（可选日志）
function checkResponsive() {
  const width = window.innerWidth;
  if (width < 768) {
    console.log('Mobile view');
  } else if (width < 1024) {
    console.log('Tablet view');
  } else {
    console.log('Desktop view');
  }
}

window.addEventListener('resize', checkResponsive);
checkResponsive();

// 11. 页面加载完成后的初始化
document.addEventListener('DOMContentLoaded', () => {
  console.log('赛博朋克2077网站已加载');
});
'''

